class TestHexToRgbErrors:
    def test_invalid_hex_characters(self):
        """Non-hex characters raise ValueError."""
        with pytest.raises(ValueError):
            hex_to_rgb(hex_color="#gghhii")

    def test_empty_string(self):
        """Empty string raises (IndexError or ValueError)."""
        with pytest.raises((ValueError, IndexError)):
            hex_to_rgb(hex_color="")

    def test_too_short(self):
        """Too-short hex string raises (ValueError or IndexError)."""
        with pytest.raises((ValueError, IndexError)):
            hex_to_rgb(hex_color="#ff")


class TestAtomicWriteJsonError:
    def test_write_failure_propagates_exception(self, tmp_path):
        """OSError from open propagates to the caller."""
        path = tmp_path / "fail.json"
        with patch("builtins.open", side_effect=OSError("disk full")):
            with pytest.raises(OSError, match="disk full"):
                atomic_write_json(data={"a": 1}, path=path)


class TestHookServerOversizedPayload:
    def test_oversized_payload_returns_413(self):
        """Payload exceeding 64 KB limit returns HTTP 413."""
        server = HookServer(
            on_hook_event=lambda *a, **kw: None,
            on_session_end=lambda s: None,
            port=0,
        )
        server.start()

        try:
            # _MAX_PAYLOAD_BYTES is 65536; send content-length above that
            oversized = json.dumps({"data": "x" * 70000}).encode()
            req = urllib.request.Request(
                f"http://127.0.0.1:{server.port}/hook",
                data=oversized,
                headers={
                    "Content-Type": "application/json",
                    "Content-Length": str(len(oversized)),
                },
                method="POST",
            )
            try:
                urllib.request.urlopen(req, timeout=5)
                assert False, "Expected HTTP 413 error"
            except urllib.error.HTTPError as e:
                assert e.code == 413
        finally:
            server.stop()
